features.snippet:
reg [1:0] fsm_addr;
wire [1:0] fsm_addr_next;
wire fsm_state;
always @(posedge clk) fsm_addr <= fsm_addr_next;
assign fsm_addr_next = fsm_state ? fsm_addr : 2'b11;

reg [1:0] fsm_addr;
reg fsm_state;
wire [3:0] led;
always @(posedge clk) begin
  fsm_state <= fsm_state ? 1'b1 : 1'b0;
  fsm_addr <= fsm_state ? fsm_addr : 2'b11;
end
assign led = 4'b1 << fsm_addr;
